Author: Z572 <zhengjunjie@iscas.ac.cn>
Date:   Wed Nov 15 23:30:08 2023 +0800

    [InstCombine] Simplifiy `sdiv -X, X` into `X == INT_MIN ? 1 : -1` (#71768)

    Alive2: https://alive2.llvm.org/ce/z/dHddwH
    Fixes #69574

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
index db0804380855..d6fac88a39d0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
@@ -1544,6 +1544,13 @@ Instruction *InstCombinerImpl::visitSDiv(BinaryOperator &I) {
     }
   }

+  // -X / X --> X == INT_MIN ? 1 : -1
+  if (isKnownNegation(Op0, Op1)) {
+    APInt MinVal = APInt::getSignedMinValue(Ty->getScalarSizeInBits());
+    Value *Cond = Builder.CreateICmpEQ(Op0, ConstantInt::get(Ty, MinVal));
+    return SelectInst::Create(Cond, ConstantInt::get(Ty, 1),
+                              ConstantInt::getAllOnesValue(Ty));
+  }
   return nullptr;
 }

tests.source_program:
define i32 @sdiv_sub2(i32 %arg) {
  %neg = sub i32 0, %arg
  %div = sdiv i32 %arg, %neg
  ret i32 %div
}

define i32 @sdiv_sub_sub(i32 %x, i32 %y) {
  %s = sub i32 %x, %y
  %u = sub i32 %y, %x
  %d = sdiv i32 %s, %u
  ret i32 %d
}

define i32 @sdiv_mul_sub_nsw(i32 %x, i32 %y) {
  %m = mul i32 %y, %x
  %n = sub nsw i32 0, %m
  %d = sdiv i32 %m, %n
  ret i32 %d
}

define i32 @sdiv_sub1(i32 %arg) {
  %neg = sub i32 0, %arg
  %div = sdiv i32 %neg, %arg
  ret i32 %div
}

define i32 @sdiv_mul_nsw_sub_nsw(i32 %x, i32 %y) {
  %m = mul nsw i32 %y, %x
  %n = sub nsw i32 0, %m
  %d = sdiv i32 %m, %n
  ret i32 %d
}

define <2 x i8> @sdiv_sdiv_mul_nsw(<2 x i8> %x, <2 x i8> %y, <2 x i8> %z) {
  %m = mul nsw <2 x i8> %y, %x
  %d = sdiv <2 x i8> %m, %z
  %r = sdiv <2 x i8> %d, %x
  ret <2 x i8> %r
}

define i32 @sdiv_mul_sub(i32 %x, i32 %y) {
  %m = mul i32 %y, %x
  %d = sub i32 0, %m
  %r = sdiv i32 %d, %m
  ret i32 %r
}

define i8 @sdiv_sdiv_mul_nsw_exact_exact(i8 %x, i8 %y, i8 %z) {
  %m = mul nsw i8 %x, %y
  %d = sdiv exact i8 %m, %z
  %r = sdiv exact i8 %d, %x
  ret i8 %r
}

issue.body:
The following two functions can be evaluated as true.
```cpp
bool f(int a, int b)
{
   return (-a * b) / (a * b);
}

bool g(int a, int b)
{
   return (-a + b) / (a - b);
}
```

https://godbolt.org/z/sa5nTd9ob
https://alive2.llvm.org/ce/z/c5EBFp

GCC and MSVC can simplify the function `f`.
